    fn export_graph_includes_all_nodes_and_only_active_edges() {
        let graph = store();
        add_node(&graph, "artifact:a", NodeType::Artifact, "a", NOW);
        add_node(&graph, "artifact:b", NodeType::Artifact, "b", NOW);
        add_node(&graph, "artifact:c", NodeType::Artifact, "c", NOW);
        graph
            .upsert_edge(&raw_edge(
                "artifact:a",
                "artifact:b",
                RelationType::Imports,
                1.0,
                168.0,
                NOW,
            ))
            .unwrap();
        graph
            .upsert_edge(&raw_edge(
                "artifact:b",
                "artifact:c",
                RelationType::RelatesTo,
                0.01,
                1.0,
                NOW - 10 * HOUR,
            ))
            .unwrap();

        let export = graph.export_graph(NOW).unwrap();

        assert_eq!(export.schema_version, 1);
        assert_eq!(export.nodes.len(), 3);
        assert_eq!(export.edges.len(), 1);
        assert_eq!(export.edges[0].relation, RelationType::Imports);
    }

    #[test]
    fn backup_database_preserves_graph_state() {
        let graph = store();
        add_node(&graph, "artifact:a", NodeType::Artifact, "a", NOW);
        let path = std::env::temp_dir().join(format!(
            "mindleak-graph-backup-{}-{}.db",
            std::process::id(),
            NOW
        ));
        let _ = std::fs::remove_file(&path);

        graph.backup_database(&path).unwrap();

        let restored = GraphStore::new(db::open(path.to_str().unwrap()).unwrap());
        assert!(restored.get_node("artifact:a").unwrap().is_some());
        drop(restored);
        std::fs::remove_file(path).unwrap();
    }

    #[test]
    fn reopened_legacy_edge_uses_the_new_read_time_policy() {
        let path = std::env::temp_dir().join(format!(
            "mindleak-policy-reopen-{}-{}.db",
            std::process::id(),
            NOW
        ));
        let _ = std::fs::remove_file(&path);
        {
            let graph = GraphStore::new(db::open(path.to_str().unwrap()).unwrap());
            add_node(&graph, "artifact:a", NodeType::Artifact, "a", NOW);
            add_node(&graph, "artifact:b", NodeType::Artifact, "b", NOW);
            graph
                .upsert_edge(&raw_edge(
                    "artifact:a",
                    "artifact:b",
                    RelationType::Modified,
                    1.0,
                    37.0,
                    NOW,
                ))
                .unwrap();
        }

        let graph = GraphStore::new(db::open(path.to_str().unwrap()).unwrap());
        let legacy = graph
            .traverse(
                &["artifact:a".to_string()],
                Direction::Outgoing,
                1,
                0.0,
                NOW,
            )
            .unwrap();
        assert_eq!(legacy.edges[0].half_life_hours, 37.0);
        drop(graph);

        let graph = GraphStore::new(db::open(path.to_str().unwrap()).unwrap())
            .with_decay_policy(policy(&[(RelationType::Modified, 48.0)], 0.05));
        let traversed = graph
            .traverse(
                &["artifact:a".to_string()],
                Direction::Outgoing,
                1,
                0.0,
                NOW,
            )
            .unwrap();

        assert_eq!(traversed.edges[0].half_life_hours, 48.0);
        drop(graph);
        std::fs::remove_file(path).unwrap();
    }

    #[test]
    fn reset_database_requires_exact_token_and_clears_memory_state() {
        let graph = store();
        add_node(&graph, "artifact:a", NodeType::Artifact, "a", NOW);
        crate::embed::upsert(&graph.conn, "artifact:a", "test", &[1.0], NOW).unwrap();
        crate::telemetry::record(
            &graph.conn,
            NOW,
            "tool_call",
            "graph_stats",
            "ok",
            Some(1),
            None,
        )
        .unwrap();

        assert!(graph.reset_database("yes").is_err());
        assert!(graph.get_node("artifact:a").unwrap().is_some());

        let outcome = graph.reset_database("RESET MINDLEAK").unwrap();
        assert_eq!(outcome.nodes_removed, 1);
        assert_eq!(outcome.embeddings_removed, 1);
        assert_eq!(outcome.telemetry_events_removed, 1);
        assert_eq!(graph.counts(NOW).unwrap(), (0, 0));
    }

    #[test]
    fn prune_removes_decayed_edges_and_orphan_executions() {
        let s = store();
        add_node(&s, "a", NodeType::Artifact, "a", NOW);
        add_node(&s, "c", NodeType::Artifact, "c", NOW);
        add_node(&s, "b", NodeType::Artifact, "b", NOW);
        add_node(
            &s,
            "execution:orphan",
            NodeType::Execution,
            "orphan run",
            NOW,
        );
        s.upsert_edge(&raw_edge("a", "c", RelationType::Calls, 1.0, 168.0, NOW))
            .unwrap();
        s.upsert_edge(&raw_edge(
            "a",
            "b",
            RelationType::Modified,
            1.0,
            1.0,
            NOW - 10 * HOUR,
        ))
        .unwrap();

        let outcome = s.prune_with_signal(NOW).unwrap();
        assert_eq!(outcome.edges_removed, 1); // only the decayed a->b
        assert_eq!(outcome.nodes_removed, 1); // the orphan execution node
        assert!(s.get_node("execution:orphan").unwrap().is_none());
        assert!(s.get_node("a").unwrap().is_some());
    }

    #[test]
    fn prune_removes_removed_symbol_after_historical_edges_decay() {
        let s = store();
        let owner = Node::new("artifact:a", NodeType::Artifact, "a", NOW);
        let symbol = Node::new("symbol:a:old", NodeType::Symbol, "old", NOW);
        let contains = Edge::new("artifact:a", "symbol:a:old", RelationType::Contains, NOW);
        s.replace_structure("artifact:a", &[owner.clone(), symbol], &[contains], &[])
            .unwrap();
        add_node(&s, "agent:a", NodeType::Agent, "a", NOW);
        s.upsert_edge(&raw_edge(
            "agent:a",
            "symbol:a:old",
            RelationType::Observed,
            1.0,
            1.0,
            NOW - 10 * HOUR,
        ))
        .unwrap();

        s.replace_structure("artifact:a", &[owner], &[], &[])
            .unwrap();
        assert!(s.get_node("symbol:a:old").unwrap().is_some());

        let outcome = s.prune_with_signal(NOW).unwrap();
        assert_eq!(outcome.edges_removed, 1);
        assert_eq!(outcome.nodes_removed, 1);
        assert!(s.get_node("symbol:a:old").unwrap().is_none());
        assert!(s.search_nodes("old", 5).unwrap().is_empty());
    }

    #[test]
    fn impact_radius_does_not_cross_agent_observations() {
        let s = store();
        add_node(&s, "artifact:a", NodeType::Artifact, "a", NOW);
        add_node(&s, "artifact:b", NodeType::Artifact, "b", NOW);
        add_node(&s, "agent:shared", NodeType::Agent, "shared", NOW);
        for target in ["artifact:a", "artifact:b"] {
            s.upsert_edge(&raw_edge(
                "agent:shared",
                target,
                RelationType::Observed,
                1.0,
                48.0,
                NOW,
            ))
            .unwrap();
        }

        let impact = s.impact_radius(&["artifact:a".into()], NOW).unwrap();
        assert!(!impact
            .nodes
            .iter()
            .any(|node| node.node.id == "agent:shared"));
        assert!(!impact.nodes.iter().any(|node| node.node.id == "artifact:b"));
        assert!(impact
            .edges
            .iter()
            .all(|edge| edge.relation != RelationType::Observed));
    }

    #[test]
    fn impact_radius_does_not_cross_to_coimported_dependencies() {
        let s = store();
        for id in ["artifact:a", "artifact:b", "artifact:consumer"] {
            add_node(&s, id, NodeType::Artifact, id, NOW);
        }
        for target in ["artifact:a", "artifact:b"] {
            s.upsert_edge(&raw_edge(
                "artifact:consumer",
                target,
                RelationType::Imports,
                1.0,
                168.0,
                NOW,
            ))
            .unwrap();
        }

        let impact = s.impact_radius(&["artifact:a".into()], NOW).unwrap();
        assert!(impact
            .nodes
            .iter()
            .any(|node| node.node.id == "artifact:consumer"));
        assert!(!impact.nodes.iter().any(|node| node.node.id == "artifact:b"));
    }

    #[test]
    fn boost_updates_attention_without_reviving_incident_evidence() {
        // Regression: focusing an artifact revived old failures and modifications;
        // node-only attention must leave every incident edge's decay clock intact.
        let s = store();
        add_node(&s, "a", NodeType::Artifact, "a", NOW - HOUR);
        add_node(&s, "b", NodeType::Artifact, "b", NOW);
        s.upsert_edge(&raw_edge(
            "a",
            "b",
            RelationType::Modified,
            1.0,
            1.0,
            NOW - 10 * HOUR,
        ))
        .unwrap();

        let before = s
            .traverse(&["a".into()], Direction::Outgoing, 1, 0.05, NOW)
            .unwrap();
        assert!(!before.nodes.iter().any(|n| n.node.id == "b"));

        assert!(s.boost("a", NOW).unwrap());
        assert!(!s.boost("missing", NOW).unwrap());

        let after = s
            .traverse(&["a".into()], Direction::Outgoing, 1, 0.05, NOW)
            .unwrap();
        assert!(!after.nodes.iter().any(|n| n.node.id == "b"));
        assert_eq!(s.get_node("a").unwrap().unwrap().last_accessed_at, NOW);
    }

    #[test]
    fn counts_reflects_active_edges_only() {
        let s = store();
        add_node(&s, "a", NodeType::Artifact, "a", NOW);
        add_node(&s, "b", NodeType::Artifact, "b", NOW);
        s.upsert_edge(&raw_edge("a", "b", RelationType::Calls, 1.0, 168.0, NOW))
            .unwrap();
        s.upsert_edge(&raw_edge(
            "b",
            "a",
            RelationType::Modified,
            1.0,
            1.0,
            NOW - 10 * HOUR,
        ))
        .unwrap();

        let (nodes, active_edges) = s.counts(NOW).unwrap();
        assert_eq!(nodes, 2);
        assert_eq!(active_edges, 1); // decayed b->a excluded
    }

    #[test]
    fn list_agents_reports_observation_counts() {
        let s = store();
        add_node(&s, "agent:a", NodeType::Agent, "a", NOW);
        add_node(&s, "artifact:x", NodeType::Artifact, "x", NOW);
        s.upsert_edge(&raw_edge(
            "agent:a",
            "artifact:x",
            RelationType::Observed,
            1.0,
            48.0,
            NOW,
        ))
        .unwrap();
        let agents = s.list_agents(NOW).unwrap();
        assert_eq!(agents.len(), 1);
        assert_eq!(agents[0].id, "agent:a");
        assert_eq!(agents[0].observations, 1);
    }

